        'index_a_48': "Piraci HIC",
        'index_a_49': "Odwiedź Patreona!",
        'index_a_50': "Zobaczmy mapę!",
        'index_strong_51': "Kapitan Zoe:",
        'index_strong_52': "Nawigator:",
        'index_strong_53': "Gubernator:",
        'index_strong_54': "Jeksamat Snajper:",
        'index_strong_55': "Meerwolf Mechanik:",
        'index_strong_56': "Odkrywca:",
