        'index_li_85': "<strong data-lang=\"index_strong_62\">Godziny otwarcia:</strong> Kiedy wieje wiatr! (0:00-24:00)",
        'vilagterkep_h1_1': "<strong>Mapa Abrigo</strong>",
        'vilagterkep_h3_2': "Góry Dragon Ridge",
